window.AmazingTitlesWiki = {"site":{"title":"AmazingTitles Wiki","defaultPage":"Home.md","tagline":"Beautiful static HTML documentation generated from the local Markdown wiki."},"nav":[{"title":"Home","path":"Home.md","children":[]},{"title":"Welcome","path":"README.md","children":[]},{"title":"Documentation","path":null,"children":[{"title":"Overview","path":"documentation/README.md","children":[]},{"title":"Quickstart","path":"documentation/getting-started.md","children":[]},{"title":"Installation and Setup","path":"documentation/installation-and-setup.md","children":[]},{"title":"Plugin Details","path":"plugin-details.md","children":[]},{"title":"Plugin Functions","path":"functions/plugin-functions.md","children":[]},{"title":"Sending Animations","path":"functions/sending-animations.md","children":[]},{"title":"Sending Notifications","path":"functions/sending-notifications.md","children":[]},{"title":"Sending Interactive Messages","path":"functions/sending-interactive-messages.md","children":[]},{"title":"HEX and Gradient Colors","path":"functions/hex-and-gradient-colors.md","children":[]},{"title":"Extensions and Integrations","path":"documentation/extensions-and-integrations.md","children":[]}]},{"title":"Animations","path":null,"children":[{"title":"NONE","path":"animations/none.md","children":[]},{"title":"PULSING","path":"animations/pulsing.md","children":[]},{"title":"RAINBOW","path":"animations/rainbow.md","children":[]},{"title":"SPLIT","path":"animations/split.md","children":[]},{"title":"WAVES","path":"animations/waves.md","children":[]},{"title":"WORDS_SPLIT","path":"animations/words-split.md","children":[]},{"title":"BOUNCE","path":"animations/bounce.md","children":[]},{"title":"FADE_IN","path":"animations/fade-in.md","children":[]},{"title":"FADE_IN_WRITER","path":"animations/fade-in-writer.md","children":[]},{"title":"FLASHING","path":"animations/flashing.md","children":[]},{"title":"FLASHING_SYMBOL_WRAP","path":"animations/flashing-symbol-wrap.md","children":[]},{"title":"FROM_BOTH_SIDES","path":"animations/from-both-sides.md","children":[]},{"title":"FROM_RIGHT","path":"animations/from-right.md","children":[]},{"title":"FROM_LEFT","path":"animations/from-left.md","children":[]}]},{"title":"API Reference","path":null,"children":[{"title":"Overview","path":"api-reference/README.md","children":[]},{"title":"Creating AmazingExtension","path":"api/creating-amazingextension.md","children":[]},{"title":"Creating Custom Animations","path":"api/creating-custom-animations.md","children":[]},{"title":"Creating Custom SubCommand","path":"api/creating-custom-subcommand.md","children":[]},{"title":"Other API Stuff","path":"api/other-api-stuff.md","children":[]}]},{"title":"Integrations","path":null,"children":[{"title":"CMI Integration","path":"integrations/cmi-integration.md","children":[]}]},{"title":"Extensions","path":null,"children":[{"title":"Overview","path":"extensions/overview.md","children":[]}]},{"title":"Changelog","path":"changelog.md","children":[]},{"title":"Help Center","path":"help-center.md","children":[]}],"pages":{"animations/bounce.md":{"title":"BOUNCE","path":"animations/bounce.md","html":"<h1 id=\"bounce\">BOUNCE</h1>\n<p><code>BOUNCE</code> is the built-in two-color bounce animation. It creates a mirrored moving highlight and then reverses it.</p>\n<h2 id=\"arguments\">Arguments</h2>\n<ul><li><code>Color1(Hex/Legacy)</code></li><li><code>Color2(Hex/Legacy)</code></li></ul>\n<h2 id=\"notes\">Notes</h2>\n<ul><li>this is the default built-in bounce</li><li>additional bounce-themed variations can be supplied by extensions</li></ul>\n<h2 id=\"example\">Example</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation all p:TITLE,d:4,fps:14 BOUNCE #FFAA00 #FFFFFF &amp;6Season reset</code></pre>","headings":[{"level":"1","id":"bounce","title":"BOUNCE"},{"level":"2","id":"arguments","title":"Arguments"},{"level":"2","id":"notes","title":"Notes"},{"level":"2","id":"example","title":"Example"}],"excerpt":"BOUNCE is the built-in two-color bounce animation. It creates a mirrored moving highlight and then reverses it."},"animations/fade-in-writer.md":{"title":"FADE_IN_WRITER","path":"animations/fade-in-writer.md","html":"<h1 id=\"fadeinwriter\">FADE_IN_WRITER</h1>\n<p><code>FADE_IN_WRITER</code> reveals text one character at a time while showing a writer symbol at the end.</p>\n<h2 id=\"arguments\">Arguments</h2>\n<ul><li><code>Writer(Single Word)</code></li></ul>\n<h2 id=\"example\">Example</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation all p:TITLE,d:4,fps:15 FADE_IN_WRITER | &amp;bCreating world</code></pre>\n<h2 id=\"tip\">Tip</h2>\n<p>Use a short writer symbol such as <code>|</code>, <code>_</code>, or <code>.</code> for the cleanest result.</p>","headings":[{"level":"1","id":"fadeinwriter","title":"FADE_IN_WRITER"},{"level":"2","id":"arguments","title":"Arguments"},{"level":"2","id":"example","title":"Example"},{"level":"2","id":"tip","title":"Tip"}],"excerpt":"FADE_IN_WRITER reveals text one character at a time while showing a writer symbol at the end."},"animations/fade-in.md":{"title":"FADE_IN","path":"animations/fade-in.md","html":"<h1 id=\"fadein\">FADE_IN</h1>\n<p><code>FADE_IN</code> reveals text progressively from left to right, preserving existing color formatting.</p>\n<h2 id=\"arguments\">Arguments</h2>\n<ul><li>none</li></ul>\n<h2 id=\"example\">Example</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation all p:TITLE,d:4,fps:20 FADE_IN &amp;dWelcome back</code></pre>","headings":[{"level":"1","id":"fadein","title":"FADE_IN"},{"level":"2","id":"arguments","title":"Arguments"},{"level":"2","id":"example","title":"Example"}],"excerpt":"FADE_IN reveals text progressively from left to right, preserving existing color formatting."},"animations/flashing-symbol-wrap.md":{"title":"FLASHING_SYMBOL_WRAP","path":"animations/flashing-symbol-wrap.md","html":"<h1 id=\"flashingsymbolwrap\">FLASHING_SYMBOL_WRAP</h1>\n<p><code>FLASHING_SYMBOL_WRAP</code> alternates between plain text and a wrapped version surrounded by a symbol.</p>\n<h2 id=\"arguments\">Arguments</h2>\n<ul><li><code>Symbol(Text)</code></li></ul>\n<h2 id=\"example\">Example</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation all p:TITLE,d:4,fps:8 FLASHING_SYMBOL_WRAP * &amp;eEvent starting</code></pre>","headings":[{"level":"1","id":"flashingsymbolwrap","title":"FLASHING_SYMBOL_WRAP"},{"level":"2","id":"arguments","title":"Arguments"},{"level":"2","id":"example","title":"Example"}],"excerpt":"FLASHING_SYMBOL_WRAP alternates between plain text and a wrapped version surrounded by a symbol."},"animations/flashing.md":{"title":"FLASHING","path":"animations/flashing.md","html":"<h1 id=\"flashing\">FLASHING</h1>\n<p><code>FLASHING</code> alternates between visible text and an empty frame.</p>\n<h2 id=\"arguments\">Arguments</h2>\n<ul><li>none</li></ul>\n<h2 id=\"best-use-cases\">Best use cases</h2>\n<ul><li>urgent warnings</li><li>countdown alerts</li><li>short action bar emphasis</li></ul>\n<h2 id=\"example\">Example</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation all p:ACTIONBAR,d:3,fps:8 FLASHING &amp;cLow health</code></pre>","headings":[{"level":"1","id":"flashing","title":"FLASHING"},{"level":"2","id":"arguments","title":"Arguments"},{"level":"2","id":"best-use-cases","title":"Best use cases"},{"level":"2","id":"example","title":"Example"}],"excerpt":"FLASHING alternates between visible text and an empty frame."},"animations/from-both-sides.md":{"title":"FROM_BOTH_SIDES","path":"animations/from-both-sides.md","html":"<h1 id=\"frombothsides\">FROM_BOTH_SIDES</h1>\n<p><code>FROM_BOTH_SIDES</code> simulates a center join by separating the text and closing the gap over time.</p>\n<h2 id=\"arguments\">Arguments</h2>\n<ul><li>none</li></ul>\n<h2 id=\"example\">Example</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation all p:TITLE,d:4,fps:18 FROM_BOTH_SIDES &amp;dMatch found</code></pre>","headings":[{"level":"1","id":"frombothsides","title":"FROM_BOTH_SIDES"},{"level":"2","id":"arguments","title":"Arguments"},{"level":"2","id":"example","title":"Example"}],"excerpt":"FROM_BOTH_SIDES simulates a center join by separating the text and closing the gap over time."},"animations/from-left.md":{"title":"FROM_LEFT","path":"animations/from-left.md","html":"<h1 id=\"fromleft\">FROM_LEFT</h1>\n<p><code>FROM_LEFT</code> slides the text in from the left side using spacing-based reveal frames.</p>\n<h2 id=\"arguments\">Arguments</h2>\n<ul><li>none</li></ul>\n<h2 id=\"example\">Example</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation all p:TITLE,d:4,fps:18 FROM_LEFT &amp;aQuest completed</code></pre>","headings":[{"level":"1","id":"fromleft","title":"FROM_LEFT"},{"level":"2","id":"arguments","title":"Arguments"},{"level":"2","id":"example","title":"Example"}],"excerpt":"FROM_LEFT slides the text in from the left side using spacing-based reveal frames."},"animations/from-right.md":{"title":"FROM_RIGHT","path":"animations/from-right.md","html":"<h1 id=\"fromright\">FROM_RIGHT</h1>\n<p><code>FROM_RIGHT</code> slides the text in from the right side using spacing-based reveal frames.</p>\n<h2 id=\"arguments\">Arguments</h2>\n<ul><li>none</li></ul>\n<h2 id=\"example\">Example</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation all p:TITLE,d:4,fps:18 FROM_RIGHT &amp;aQuest completed</code></pre>","headings":[{"level":"1","id":"fromright","title":"FROM_RIGHT"},{"level":"2","id":"arguments","title":"Arguments"},{"level":"2","id":"example","title":"Example"}],"excerpt":"FROM_RIGHT slides the text in from the right side using spacing-based reveal frames."},"animations/none.md":{"title":"NONE","path":"animations/none.md","html":"<h1 id=\"none\">NONE</h1>\n<p><code>NONE</code> is the simplest built-in animation. It sends a single static frame.</p>\n<h2 id=\"arguments\">Arguments</h2>\n<ul><li>none</li></ul>\n<h2 id=\"best-use-cases\">Best use cases</h2>\n<ul><li>plain titles</li><li>plain subtitles</li><li>static action bars</li><li>boss bar text without animation</li></ul>\n<h2 id=\"example\">Example</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation all p:TITLE,d:3,fps:20 NONE &amp;aWelcome to the server</code></pre>","headings":[{"level":"1","id":"none","title":"NONE"},{"level":"2","id":"arguments","title":"Arguments"},{"level":"2","id":"best-use-cases","title":"Best use cases"},{"level":"2","id":"example","title":"Example"}],"excerpt":"NONE is the simplest built-in animation. It sends a single static frame."},"animations/pulsing.md":{"title":"PULSING","path":"animations/pulsing.md","html":"<h1 id=\"pulsing\">PULSING</h1>\n<p><code>PULSING</code> fades text between two colors over time.</p>\n<h2 id=\"arguments\">Arguments</h2>\n<ul><li><code>Color1(Hex/Legacy)</code></li><li><code>Color2(Hex/Legacy)</code></li></ul>\n<h2 id=\"notes\">Notes</h2>\n<ul><li>works best on RGB-capable versions</li><li>useful for premium title screens and status highlights</li></ul>\n<h2 id=\"example\">Example</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation all p:TITLE,d:4,fps:20 PULSING #00AAFF #FFFFFF &amp;bLoading profile</code></pre>","headings":[{"level":"1","id":"pulsing","title":"PULSING"},{"level":"2","id":"arguments","title":"Arguments"},{"level":"2","id":"notes","title":"Notes"},{"level":"2","id":"example","title":"Example"}],"excerpt":"PULSING fades text between two colors over time."},"animations/rainbow.md":{"title":"RAINBOW","path":"animations/rainbow.md","html":"<h1 id=\"rainbow\">RAINBOW</h1>\n<p><code>RAINBOW</code> sweeps multiple gradient phases across the text.</p>\n<h2 id=\"arguments\">Arguments</h2>\n<ul><li>none</li></ul>\n<h2 id=\"notes\">Notes</h2>\n<ul><li>uses RGB output</li><li>strongest on modern versions with full HEX support</li></ul>\n<h2 id=\"example\">Example</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation all p:TITLE,d:4,fps:20 RAINBOW &amp;lAmazingTitles</code></pre>","headings":[{"level":"1","id":"rainbow","title":"RAINBOW"},{"level":"2","id":"arguments","title":"Arguments"},{"level":"2","id":"notes","title":"Notes"},{"level":"2","id":"example","title":"Example"}],"excerpt":"RAINBOW sweeps multiple gradient phases across the text."},"animations/split.md":{"title":"SPLIT","path":"animations/split.md","html":"<h1 id=\"split\">SPLIT</h1>\n<p><code>SPLIT</code> turns one text body into multiple frames using the <code>%frame%</code> delimiter.</p>\n<h2 id=\"arguments\">Arguments</h2>\n<ul><li>none</li></ul>\n<h2 id=\"input-rule\">Input rule</h2>\n<p>Place <code>%frame%</code> inside the main text wherever you want to cut frames.</p>\n<h2 id=\"example\">Example</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation all p:ACTIONBAR,d:4,fps:6 SPLIT &amp;aLoading%frame%&amp;eLoading.%frame%&amp;6Loading..</code></pre>","headings":[{"level":"1","id":"split","title":"SPLIT"},{"level":"2","id":"arguments","title":"Arguments"},{"level":"2","id":"input-rule","title":"Input rule"},{"level":"2","id":"example","title":"Example"}],"excerpt":"SPLIT turns one text body into multiple frames using the %frame% delimiter."},"animations/waves.md":{"title":"WAVES","path":"animations/waves.md","html":"<h1 id=\"waves\">WAVES</h1>\n<p><code>WAVES</code> animates a two-color sweep that moves across the text and back.</p>\n<h2 id=\"arguments\">Arguments</h2>\n<ul><li><code>Color1(HEX/Legacy)</code></li><li><code>Color2(HEX/Legacy)</code></li></ul>\n<h2 id=\"best-use-cases\">Best use cases</h2>\n<ul><li>action bars</li><li>loading states</li><li>rotating announcements</li></ul>\n<h2 id=\"example\">Example</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation all p:ACTIONBAR,d:5,fps:12 WAVES #00AAFF #FFFFFF &amp;bSynchronizing...</code></pre>","headings":[{"level":"1","id":"waves","title":"WAVES"},{"level":"2","id":"arguments","title":"Arguments"},{"level":"2","id":"best-use-cases","title":"Best use cases"},{"level":"2","id":"example","title":"Example"}],"excerpt":"WAVES animates a two-color sweep that moves across the text and back."},"animations/words-split.md":{"title":"WORDS_SPLIT","path":"animations/words-split.md","html":"<h1 id=\"wordssplit\">WORDS_SPLIT</h1>\n<p><code>WORDS_SPLIT</code> treats each space-separated word as a frame.</p>\n<h2 id=\"arguments\">Arguments</h2>\n<ul><li>none</li></ul>\n<h2 id=\"input-rule\">Input rule</h2>\n<p>The text is split by spaces.</p>\n<h2 id=\"example\">Example</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation all p:TITLE,d:4,fps:8 WORDS_SPLIT Ready Set Go</code></pre>","headings":[{"level":"1","id":"wordssplit","title":"WORDS_SPLIT"},{"level":"2","id":"arguments","title":"Arguments"},{"level":"2","id":"input-rule","title":"Input rule"},{"level":"2","id":"example","title":"Example"}],"excerpt":"WORDS_SPLIT treats each space-separated word as a frame."},"api/creating-amazingextension.md":{"title":"Creating AmazingExtension","path":"api/creating-amazingextension.md","html":"<h1 id=\"creating-amazingextension\">Creating AmazingExtension</h1>\n<p>This page shows the basic extension contract used by AmazingTitles.</p>\n<h2 id=\"the-interface\">The interface</h2>\n<p>An extension implements <code>AmazingExtension</code> and defines:</p>\n<ul><li><code>extension_name()</code></li><li><code>load()</code></li><li><code>unload()</code></li></ul>\n<p>It also inherits helpers such as:</p>\n<ul><li><code>addListener(...)</code></li><li><code>getPluginInstance()</code></li><li><code>getListeners()</code></li><li><code>unregisterListeners()</code></li></ul>\n<h2 id=\"minimal-example\">Minimal example</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-java\">package org.korastudios.amazingtitles.extension.example;\n\nimport org.korastudios.amazingtitles.code.api.interfaces.AmazingExtension;\n\npublic class Main implements AmazingExtension {\n\n    @Override\n    public String extension_name() {\n        return &quot;Example&quot;;\n    }\n\n    @Override\n    public void load() {\n        // Register animations here\n    }\n\n    @Override\n    public void unload() {\n        unregisterListeners();\n    }\n}</code></pre>\n<h2 id=\"required-metadata\">Required metadata</h2>\n<p>Your jar must include <code>extension.yml</code>:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-yaml\">Class: org.korastudios.amazingtitles.extension.example.Main</code></pre>\n<h2 id=\"loading-behavior\">Loading behavior</h2>\n<p>AmazingTitles scans the <code>Extensions</code> folder for jar files, reads <code>extension.yml</code>, and instantiates the configured class with a no-args constructor.</p>\n<h2 id=\"recommendations\">Recommendations</h2>\n<ul><li>keep <code>load()</code> focused on registration</li><li>keep <code>unload()</code> focused on cleanup</li><li>do not leave listeners registered after unload</li><li>prefer unique animation keys such as <code>EXTENSION_EXAMPLE_MY_ANIMATION</code></li></ul>","headings":[{"level":"1","id":"creating-amazingextension","title":"Creating AmazingExtension"},{"level":"2","id":"the-interface","title":"The interface"},{"level":"2","id":"minimal-example","title":"Minimal example"},{"level":"2","id":"required-metadata","title":"Required metadata"},{"level":"2","id":"loading-behavior","title":"Loading behavior"},{"level":"2","id":"recommendations","title":"Recommendations"}],"excerpt":"This page shows the basic extension contract used by AmazingTitles."},"api/creating-custom-animations.md":{"title":"Creating Custom Animations","path":"api/creating-custom-animations.md","html":"<h1 id=\"creating-custom-animations\">Creating Custom Animations</h1>\n<p>Custom animations are built with <code>AnimationBuilder</code>.</p>\n<h2 id=\"core-pieces\">Core pieces</h2>\n<ul><li><code>AnimationBuilder</code></li><li><code>AnimationType</code></li><li><code>ComponentArguments</code></li><li><code>FramesBuilder</code></li></ul>\n<h2 id=\"animation-types\">Animation types</h2>\n<p>Current enum values:</p>\n<ul><li><code>REPEATING</code></li><li><code>FADE_IN</code></li><li><code>LIGHT</code></li></ul>\n<h2 id=\"example-animation\">Example animation</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-java\">package org.korastudios.amazingtitles.extension.example;\n\nimport org.bukkit.boss.BarColor;\nimport org.korastudios.amazingtitles.code.api.builders.AnimationBuilder;\nimport org.korastudios.amazingtitles.code.api.enums.AnimationType;\nimport org.korastudios.amazingtitles.code.api.enums.DisplayType;\nimport org.korastudios.amazingtitles.code.api.interfaces.AmazingExtension;\nimport org.korastudios.amazingtitles.code.internal.components.ComponentArguments;\nimport org.korastudios.amazingtitles.code.internal.utils.ColorTranslator;\n\nimport java.util.LinkedList;\n\npublic class Main implements AmazingExtension {\n\n    @Override\n    public String extension_name() {\n        return &quot;Example&quot;;\n    }\n\n    @Override\n    public void load() {\n        AnimationBuilder builder = new AnimationBuilder(this, AnimationType.REPEATING, false, &quot;Color&quot;);\n        builder.setComponentArguments(ComponentArguments.create(&quot;Example&quot;, &quot;&quot;, BarColor.WHITE, 3, 10, DisplayType.TITLE));\n        builder.setFramesBuilder((arguments, args) -&gt; {\n            LinkedList&lt;String&gt; frames = new LinkedList&lt;&gt;();\n            String color = args.length &gt; 0 ? args[0] : &quot;&amp;a&quot;;\n            frames.add(ColorTranslator.colorize(color + arguments.getMainText()));\n            frames.add(ColorTranslator.colorize(&quot;&amp;f&quot; + arguments.getMainText()));\n            return frames;\n        });\n        builder.register(&quot;EXTENSION_EXAMPLE_FLASH&quot;);\n    }\n\n    @Override\n    public void unload() {\n    }\n}</code></pre>\n<h2 id=\"registration-flow\">Registration flow</h2>\n<ol><li>Create the builder</li><li>Set default <code>ComponentArguments</code></li><li>Set a <code>FramesBuilder</code></li><li>Register with a stable key</li></ol>\n<h2 id=\"good-naming-style\">Good naming style</h2>\n<p>Use uppercase keys with a clear family prefix:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">EXTENSION_EXAMPLE_FLASH</code></pre>\n<h2 id=\"tips\">Tips</h2>\n<ul><li>use <code>LinkedList&lt;String&gt;</code> for frame output</li><li>colorize frames before returning them</li><li>keep frame counts reasonable</li><li>document required arguments for command users</li></ul>","headings":[{"level":"1","id":"creating-custom-animations","title":"Creating Custom Animations"},{"level":"2","id":"core-pieces","title":"Core pieces"},{"level":"2","id":"animation-types","title":"Animation types"},{"level":"2","id":"example-animation","title":"Example animation"},{"level":"2","id":"registration-flow","title":"Registration flow"},{"level":"2","id":"good-naming-style","title":"Good naming style"},{"level":"2","id":"tips","title":"Tips"}],"excerpt":"Custom animations are built with AnimationBuilder."},"api/creating-custom-subcommand.md":{"title":"Creating Custom SubCommand","path":"api/creating-custom-subcommand.md","html":"<h1 id=\"creating-custom-subcommand\">Creating Custom SubCommand</h1>\n<p>AmazingTitles allows registering custom command handlers through its API.</p>\n<h2 id=\"main-interface\">Main interface</h2>\n<p>Implement <code>CommandHandler</code> and register it with:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-java\">AmazingTitles.registerCommandHandler(&quot;myHandler&quot;, handler);</code></pre>\n<h2 id=\"required-methods\">Required methods</h2>\n<ul><li><code>readAndExecute(CommandSender sender, String[] args)</code></li><li><code>readAndReturn(CommandSender sender, String[] args)</code></li><li><code>permission()</code></li><li><code>handlerType()</code></li><li><code>helpMessage()</code></li></ul>\n<h2 id=\"example\">Example</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-java\">import net.md_5.bungee.api.chat.BaseComponent;\nimport net.md_5.bungee.api.chat.TextComponent;\nimport org.bukkit.command.CommandSender;\nimport org.korastudios.amazingtitles.code.api.AmazingTitles;\nimport org.korastudios.amazingtitles.code.internal.commands.commandreaders.CommandHandler;\nimport org.korastudios.amazingtitles.code.internal.commands.commandreaders.HandlerType;\nimport org.korastudios.amazingtitles.code.internal.commands.commandreaders.InternalHandlerType;\n\nimport java.util.Collections;\nimport java.util.List;\n\npublic class MyHandler implements CommandHandler {\n\n    @Override\n    public boolean readAndExecute(CommandSender sender, String[] args) {\n        sender.sendMessage(&quot;Hello from AmazingTitles&quot;);\n        return true;\n    }\n\n    @Override\n    public List&lt;String&gt; readAndReturn(CommandSender sender, String[] args) {\n        return Collections.singletonList(&quot;example&quot;);\n    }\n\n    @Override\n    public String permission() {\n        return &quot;at.custom&quot;;\n    }\n\n    @Override\n    public HandlerType handlerType() {\n        return new InternalHandlerType();\n    }\n\n    @Override\n    public BaseComponent[] helpMessage() {\n        return new BaseComponent[] { new TextComponent(&quot;/at myHandler&quot;) };\n    }\n}</code></pre>\n<h2 id=\"register-and-unregister\">Register and unregister</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-java\">AmazingTitles.registerCommandHandler(&quot;myHandler&quot;, new MyHandler());\nAmazingTitles.unregisterCommandHandler(&quot;myHandler&quot;);</code></pre>\n<h2 id=\"practical-use-cases\">Practical use cases</h2>\n<ul><li>admin utilities</li><li>integration shortcuts</li><li>extension-specific command entry points</li><li>developer debugging tools</li></ul>","headings":[{"level":"1","id":"creating-custom-subcommand","title":"Creating Custom SubCommand"},{"level":"2","id":"main-interface","title":"Main interface"},{"level":"2","id":"required-methods","title":"Required methods"},{"level":"2","id":"example","title":"Example"},{"level":"2","id":"register-and-unregister","title":"Register and unregister"},{"level":"2","id":"practical-use-cases","title":"Practical use cases"}],"excerpt":"AmazingTitles allows registering custom command handlers through its API."},"api/other-api-stuff.md":{"title":"Other API Stuff","path":"api/other-api-stuff.md","html":"<h1 id=\"other-api-stuff\">Other API Stuff</h1>\n<p>This page collects useful public entry points exposed by <code>AmazingTitles</code>.</p>\n<h2 id=\"plugin-reload\">Plugin reload</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-java\">AmazingTitles.reloadPlugin();\nAmazingTitles.reloadPlugin(sender);</code></pre>\n<h2 id=\"animations\">Animations</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-java\">AmazingTitles.registerCustomAnimation(&quot;MY_ANIMATION&quot;, builder);\nAmazingTitles.unregisterCustomAnimation(&quot;MY_ANIMATION&quot;);\nAmazingTitles.getCustomAnimation(&quot;MY_ANIMATION&quot;);\nAmazingTitles.getAnimationNames();\nAmazingTitles.sendAnimation(&quot;MY_ANIMATION&quot;, arguments, args, player);\nAmazingTitles.broadcastAnimation(&quot;MY_ANIMATION&quot;, arguments, args);</code></pre>\n<h2 id=\"components-and-cache-helpers\">Components and cache helpers</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-java\">AmazingTitles.getAnimationBy(player);\nAmazingTitles.hasAnimation(player);\nAmazingTitles.removeAnimation(player);</code></pre>\n<h2 id=\"notifications\">Notifications</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-java\">AmazingTitles.sendNotification(notification, player);\nAmazingTitles.sendNotification(&quot;id&quot;, notification, players);\nAmazingTitles.broadcastNotification(notification);</code></pre>\n<h2 id=\"interactive-messages\">Interactive messages</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-java\">AmazingTitles.getInteractiveMessageFromRaw(raw);\nAmazingTitles.sendInteractiveMessage(raw, player);\nAmazingTitles.broadcastInteractiveMessage(raw);</code></pre>\n<h2 id=\"extensions\">Extensions</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-java\">AmazingTitles.loadExtension(extension);\nAmazingTitles.unloadExtension(&quot;Example&quot;);\nAmazingTitles.unloadAllExtensions();\nAmazingTitles.getLoadedExtensionNames();\nAmazingTitles.getLoadedExtensionFileNames();\nAmazingTitles.registerExtensionListener(extension, listener);</code></pre>\n<h2 id=\"smartbar-access\">SmartBar access</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-java\">AmazingTitles.getSmartBar(player);\nAmazingTitles.hideSmartBar(player);\nAmazingTitles.showSmartBar(player);</code></pre>\n<h2 id=\"system-folders\">System folders</h2>\n<p>The API exposes these shared directories:</p>\n<ul><li><code>AmazingTitles.EXTENSIONS_FOLDER</code></li><li><code>AmazingTitles.INTEGRATIONS_FOLDER</code></li></ul>\n<h2 id=\"namespace-reminder\">Namespace reminder</h2>\n<p>All current API imports should use:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">org.korastudios.amazingtitles</code></pre>","headings":[{"level":"1","id":"other-api-stuff","title":"Other API Stuff"},{"level":"2","id":"plugin-reload","title":"Plugin reload"},{"level":"2","id":"animations","title":"Animations"},{"level":"2","id":"components-and-cache-helpers","title":"Components and cache helpers"},{"level":"2","id":"notifications","title":"Notifications"},{"level":"2","id":"interactive-messages","title":"Interactive messages"},{"level":"2","id":"extensions","title":"Extensions"},{"level":"2","id":"smartbar-access","title":"SmartBar access"},{"level":"2","id":"system-folders","title":"System folders"},{"level":"2","id":"namespace-reminder","title":"Namespace reminder"}],"excerpt":"This page collects useful public entry points exposed by AmazingTitles."},"api-reference/README.md":{"title":"API Reference","path":"api-reference/README.md","html":"<h1 id=\"api-reference\">API Reference</h1>\n<p>This section is the developer-facing reference area for AmazingTitles.</p>\n<p>If you are integrating with the plugin from another module, extension, or custom feature, start here.</p>\n<h2 id=\"core-concepts\">Core concepts</h2>\n<ul><li><code>AmazingExtension</code> for extension jars</li><li><code>AnimationBuilder</code> for custom animation registration</li><li><code>AmazingTitles</code> static API helpers for runtime actions</li><li><code>ComponentArguments</code> for delivery configuration</li></ul>\n<h2 id=\"namespace\">Namespace</h2>\n<p>All current imports should use:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">org.korastudios.amazingtitles</code></pre>\n<h2 id=\"api-pages\">API pages</h2>\n<ul><li><a href=\"#/api/creating-amazingextension.md\">Creating AmazingExtension</a></li><li><a href=\"#/api/creating-custom-animations.md\">Creating Custom Animations</a></li><li><a href=\"#/api/creating-custom-subcommand.md\">Creating Custom SubCommand</a></li><li><a href=\"#/api/other-api-stuff.md\">Other API Stuff</a></li></ul>\n<h2 id=\"good-starting-points\">Good starting points</h2>\n<p>If you are building:</p>\n<ul><li>a custom effect: start with <a href=\"#/api/creating-custom-animations.md\">Creating Custom Animations</a></li><li>an extension jar: start with <a href=\"#/api/creating-amazingextension.md\">Creating AmazingExtension</a></li><li>a command integration: start with <a href=\"#/api/creating-custom-subcommand.md\">Creating Custom SubCommand</a></li></ul>\n<h2 id=\"runtime-reminder\">Runtime reminder</h2>\n<p>When publishing docs in GitBook, this section works well as the top page of an <code>API Reference</code> group because it separates developer documentation from administrator-facing usage pages.</p>","headings":[{"level":"1","id":"api-reference","title":"API Reference"},{"level":"2","id":"core-concepts","title":"Core concepts"},{"level":"2","id":"namespace","title":"Namespace"},{"level":"2","id":"api-pages","title":"API pages"},{"level":"2","id":"good-starting-points","title":"Good starting points"},{"level":"2","id":"runtime-reminder","title":"Runtime reminder"}],"excerpt":"This section is the developer-facing reference area for AmazingTitles."},"changelog.md":{"title":"Changelog","path":"changelog.md","html":"<h1 id=\"changelog\">Changelog</h1>\n<p>This page tracks notable documentation-level milestones for the current AmazingTitles codebase.</p>\n<h2 id=\"60-snapshot\">6.0-SNAPSHOT</h2>\n<p>Current working snapshot in this repository.</p>\n<p>Highlights:</p>\n<ul><li>namespace migrated to <code>org.korastudios.amazingtitles</code></li><li>support added for <code>1.8.8</code> through <code>R1_8_R3</code></li><li><code>R1_21_R1</code> aligned for <code>1.21.11</code> Paper usage</li><li>update checker moved from Spigot to GitHub Releases</li><li>extension set expanded with new themed extension modules</li><li>local wiki created and reorganized for GitBook usage</li></ul>\n<h2 id=\"previous-project-lineage\">Previous project lineage</h2>\n<p>AmazingTitles existed previously under the older namespace and documentation style. This repository now documents the current Kora Studios codebase direction.</p>\n<h2 id=\"release-source\">Release source</h2>\n<p>The plugin now checks and documents releases from:</p>\n<p><a href=\"https://github.com/Kora-Studios-LLC/AmazingTitles/releases\" target=\"_blank\" rel=\"noreferrer\">https://github.com/Kora-Studios-LLC/AmazingTitles/releases</a></p>","headings":[{"level":"1","id":"changelog","title":"Changelog"},{"level":"2","id":"60-snapshot","title":"6.0-SNAPSHOT"},{"level":"2","id":"previous-project-lineage","title":"Previous project lineage"},{"level":"2","id":"release-source","title":"Release source"}],"excerpt":"This page tracks notable documentation-level milestones for the current AmazingTitles codebase."},"documentation/extensions-and-integrations.md":{"title":"Extensions and Integrations","path":"documentation/extensions-and-integrations.md","html":"<h1 id=\"extensions-and-integrations\">Extensions and Integrations</h1>\n<p>AmazingTitles supports both external extension jars and integration scripts or files stored in the plugin data folder.</p>\n<h2 id=\"extensions\">Extensions</h2>\n<p>Extensions are loaded from:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">plugins/AmazingTitles/Extensions</code></pre>\n<p>The plugin reads <code>extension.yml</code> inside each jar and instantiates the configured main class.</p>\n<p>Use these commands to work with installed extension jars:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at pluginActions extensionList\n/at pluginActions loadExtension &lt;file&gt;\n/at pluginActions reloadExtension &lt;name&gt;\n/at pluginActions unloadExtension &lt;name&gt;\n/at pluginActions loadExtensions\n/at pluginActions reloadExtensions\n/at pluginActions unloadExtensions</code></pre>\n<p>More details:</p>\n<ul><li><a href=\"#/extensions/overview.md\">Extensions Overview</a></li><li><a href=\"#/api/creating-amazingextension.md\">Creating AmazingExtension</a></li></ul>\n<h2 id=\"integrations\">Integrations</h2>\n<p>Integrations are read from:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">plugins/AmazingTitles/Integrations</code></pre>\n<p>The most visible built-in integration path in the repository is <code>CMI</code>.</p>\n<p>More details:</p>\n<ul><li><a href=\"#/integrations/cmi-integration.md\">CMI Integration</a></li></ul>\n<h2 id=\"typical-workflow\">Typical workflow</h2>\n<ol><li>Keep the main plugin stable and configured first.</li><li>Add extension jars only after the base plugin loads normally.</li><li>Test each extension individually.</li><li>If using CMI, verify event names and conditions in your integration files.</li></ol>\n<h2 id=\"compatibility-note\">Compatibility note</h2>\n<p>Extensions compiled for this project should import:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">org.korastudios.amazingtitles</code></pre>\n<p>and should target the current AmazingTitles API instead of the legacy namespace.</p>","headings":[{"level":"1","id":"extensions-and-integrations","title":"Extensions and Integrations"},{"level":"2","id":"extensions","title":"Extensions"},{"level":"2","id":"integrations","title":"Integrations"},{"level":"2","id":"typical-workflow","title":"Typical workflow"},{"level":"2","id":"compatibility-note","title":"Compatibility note"}],"excerpt":"AmazingTitles supports both external extension jars and integration scripts or files stored in the plugin data folder."},"documentation/getting-started.md":{"title":"Quickstart","path":"documentation/getting-started.md","html":"<h1 id=\"quickstart\">Quickstart</h1>\n<p>This page is meant to be the fastest path from download to first visible animation.</p>\n<h2 id=\"1-install-the-plugin\">1. Install the plugin</h2>\n<p>Place the main plugin jar into your server <code>plugins</code> directory and start the server once.</p>\n<p>That creates the AmazingTitles data folder and its default configuration files.</p>\n<h2 id=\"2-check-your-server-version\">2. Check your server version</h2>\n<p>This build supports:</p>\n<ul><li><code>1.8.8</code> through <code>1.21.11</code></li></ul>\n<p>Notes:</p>\n<ul><li><code>1.21.11</code> is targeted through the Paper API line used in this repository</li><li><code>1.8.8</code> support uses the <code>R1_8_R3</code> provider</li><li>boss bars are not available natively on <code>1.8.8</code></li></ul>\n<h2 id=\"3-test-a-simple-animation\">3. Test a simple animation</h2>\n<p>Use one of these commands in game or from the console:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation all p:TITLE,d:3,fps:20 NONE &amp;aWelcome\n/at sendAnimation all p:TITLE,d:4,fps:15 WAVES #00AAFF #FFFFFF &amp;bServer ready</code></pre>\n<h2 id=\"4-test-a-notification\">4. Test a notification</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendNotification all 4 &amp;a+ &amp;fReward claimed</code></pre>\n<h2 id=\"5-test-an-interactive-message\">5. Test an interactive message</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendMessage all &lt;HOVER=&amp;eOpen releases,OPEN_URL=https://github.com/Kora-Studios-LLC/AmazingTitles/releases&gt;&amp;aClick here&lt;/&gt;</code></pre>\n<h2 id=\"6-add-extensions-if-needed\">6. Add extensions if needed</h2>\n<p>Drop external extension jars into:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">plugins/AmazingTitles/Extensions</code></pre>\n<p>Then use:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at pluginActions loadExtensions</code></pre>\n<h2 id=\"continue-reading\">Continue reading</h2>\n<ul><li><a href=\"#/documentation/installation-and-setup.md\">Installation and Setup</a></li><li><a href=\"#/functions/plugin-functions.md\">Plugin Functions</a></li><li><a href=\"#/extensions/overview.md\">Extensions Overview</a></li><li><a href=\"#/api-reference/README.md\">API Reference Overview</a></li></ul>","headings":[{"level":"1","id":"quickstart","title":"Quickstart"},{"level":"2","id":"1-install-the-plugin","title":"1. Install the plugin"},{"level":"2","id":"2-check-your-server-version","title":"2. Check your server version"},{"level":"2","id":"3-test-a-simple-animation","title":"3. Test a simple animation"},{"level":"2","id":"4-test-a-notification","title":"4. Test a notification"},{"level":"2","id":"5-test-an-interactive-message","title":"5. Test an interactive message"},{"level":"2","id":"6-add-extensions-if-needed","title":"6. Add extensions if needed"},{"level":"2","id":"continue-reading","title":"Continue reading"}],"excerpt":"This page is meant to be the fastest path from download to first visible animation."},"documentation/installation-and-setup.md":{"title":"Installation and Setup","path":"documentation/installation-and-setup.md","html":"<h1 id=\"installation-and-setup\">Installation and Setup</h1>\n<p>This page covers the runtime layout you will usually want before publishing the docs in GitBook.</p>\n<h2 id=\"requirements\">Requirements</h2>\n<ul><li>Java 21 to build this repository</li><li>Java compatibility at runtime according to your server platform</li><li>Spigot or Paper server within the supported range</li></ul>\n<h2 id=\"files-and-folders\">Files and folders</h2>\n<p>The plugin creates and uses these paths inside its data directory:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">plugins/AmazingTitles/\nplugins/AmazingTitles/Extensions/\nplugins/AmazingTitles/Integrations/</code></pre>\n<p>Important files commonly edited by administrators:</p>\n<ul><li><code>plugin.yml</code> inside the jar for command metadata</li><li><code>options.yml</code> for runtime options and SmartBar settings</li></ul>\n<h2 id=\"main-command\">Main command</h2>\n<p>AmazingTitles registers:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/amazingtitles\n/at</code></pre>\n<h2 id=\"permissions\">Permissions</h2>\n<p>The current codebase uses these permission nodes:</p>\n<ul><li><code>amazingtitles.command</code></li><li><code>amazingtitles.admin</code></li><li><code>at.animations</code></li><li><code>at.notifications</code></li><li><code>at.messages</code></li><li><code>at.plugin</code></li></ul>\n<h2 id=\"update-notifications\">Update notifications</h2>\n<p>The current build checks GitHub Releases instead of Spigot:</p>\n<ul><li>Releases page: <a href=\"https://github.com/Kora-Studios-LLC/AmazingTitles/releases\" target=\"_blank\" rel=\"noreferrer\">https://github.com/Kora-Studios-LLC/AmazingTitles/releases</a></li><li>API endpoint: <code>https://api.github.com/repos/Kora-Studios-LLC/AmazingTitles/releases/latest</code></li></ul>\n<h2 id=\"common-first-run-checklist\">Common first-run checklist</h2>\n<ol><li>Start the server once with the plugin installed.</li><li>Confirm the data folder was created.</li><li>Review <code>options.yml</code>.</li><li>Run a simple <code>/at sendAnimation</code> test.</li><li>Add extension jars only after the base plugin is working.</li></ol>\n<h2 id=\"related-pages\">Related pages</h2>\n<ul><li><a href=\"#/plugin-details.md\">Plugin Details</a></li><li><a href=\"#/documentation/getting-started.md\">Quickstart</a></li><li><a href=\"#/help-center.md\">Help Center</a></li></ul>","headings":[{"level":"1","id":"installation-and-setup","title":"Installation and Setup"},{"level":"2","id":"requirements","title":"Requirements"},{"level":"2","id":"files-and-folders","title":"Files and folders"},{"level":"2","id":"main-command","title":"Main command"},{"level":"2","id":"permissions","title":"Permissions"},{"level":"2","id":"update-notifications","title":"Update notifications"},{"level":"2","id":"common-first-run-checklist","title":"Common first-run checklist"},{"level":"2","id":"related-pages","title":"Related pages"}],"excerpt":"This page covers the runtime layout you will usually want before publishing the docs in GitBook."},"documentation/README.md":{"title":"Documentation","path":"documentation/README.md","html":"<h1 id=\"documentation\">Documentation</h1>\n<p>This section is the main product documentation area for AmazingTitles.</p>\n<p>If you are setting the plugin up for the first time, start with:</p>\n<ul><li><a href=\"#/documentation/getting-started.md\">Quickstart</a></li><li><a href=\"#/documentation/installation-and-setup.md\">Installation and Setup</a></li><li><a href=\"#/plugin-details.md\">Plugin Details</a></li></ul>\n<p>If you are already running the plugin and need usage examples, continue with:</p>\n<ul><li><a href=\"#/functions/plugin-functions.md\">Plugin Functions</a></li><li><a href=\"#/functions/sending-animations.md\">Sending Animations</a></li><li><a href=\"#/functions/sending-notifications.md\">Sending Notifications</a></li><li><a href=\"#/functions/sending-interactive-messages.md\">Sending Interactive Messages</a></li><li><a href=\"#/functions/hex-and-gradient-colors.md\">HEX and Gradient Colors</a></li></ul>\n<p>If you need ecosystem-level guidance, use:</p>\n<ul><li><a href=\"#/documentation/extensions-and-integrations.md\">Extensions and Integrations</a></li><li><a href=\"#/extensions/overview.md\">Extensions Overview</a></li><li><a href=\"#/integrations/cmi-integration.md\">CMI Integration</a></li></ul>\n<h2 id=\"documentation-map\">Documentation map</h2>\n<p>AmazingTitles documentation is split into a few practical layers:</p>\n<ul><li>setup and compatibility</li><li>commands and runtime usage</li><li>built-in animation behavior</li><li>extension loading and integration hooks</li><li>public API reference for developers</li></ul>\n<p>That keeps the GitBook navigation clean while still matching the real plugin structure.</p>","headings":[{"level":"1","id":"documentation","title":"Documentation"},{"level":"2","id":"documentation-map","title":"Documentation map"}],"excerpt":"This section is the main product documentation area for AmazingTitles."},"extensions/overview.md":{"title":"Extensions Overview","path":"extensions/overview.md","html":"<h1 id=\"extensions-overview\">Extensions Overview</h1>\n<p>AmazingTitles can load external extension jars from its <code>Extensions</code> folder.</p>\n<h2 id=\"extension-directory\">Extension directory</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">plugins/AmazingTitles/Extensions</code></pre>\n<h2 id=\"extension-lifecycle\">Extension lifecycle</h2>\n<p>Extensions are loaded through <code>AmazingExtension</code> and may:</p>\n<ul><li>register custom animations</li><li>register Bukkit listeners</li><li>use the public AmazingTitles API</li></ul>\n<h2 id=\"managing-extensions-in-game\">Managing extensions in-game</h2>\n<p>Use the plugin actions handler:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at pluginActions extensionList\n/at pluginActions loadExtensions\n/at pluginActions reloadExtensions\n/at pluginActions unloadExtensions\n/at pluginActions loadExtension &lt;jarName&gt;\n/at pluginActions reloadExtension &lt;extensionName&gt;\n/at pluginActions unloadExtension &lt;extensionName&gt;</code></pre>\n<h2 id=\"current-extension-families-in-this-repository\">Current extension families in this repository</h2>\n<ul><li>Summer</li><li>Winter</li><li>Alert</li><li>Bounce</li><li>Cosmic</li><li>Fire</li><li>Glow</li><li>Progress</li><li>Shockwave</li><li>Timer</li><li>Void</li></ul>\n<h2 id=\"current-source-level-extension-reference\">Current source-level extension reference</h2>\n<p>See <a href=\"../EXTENSIONS.md\">EXTENSIONS.md</a> for the current extension catalog and animation keys bundled in this repository.</p>\n<h2 id=\"extension-jar-requirements\">Extension jar requirements</h2>\n<p>Each extension jar must include an <code>extension.yml</code> file with a <code>Class:</code> entry pointing to the extension main class.</p>\n<p>Example:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-yaml\">Class: org.korastudios.amazingtitles.extension.example.Main</code></pre>\n<h2 id=\"recommended-structure\">Recommended structure</h2>\n<ul><li>one main class implementing <code>AmazingExtension</code></li><li>animation registrations inside <code>load()</code></li><li>cleanup inside <code>unload()</code></li><li>listener registration through <code>addListener(...)</code></li></ul>","headings":[{"level":"1","id":"extensions-overview","title":"Extensions Overview"},{"level":"2","id":"extension-directory","title":"Extension directory"},{"level":"2","id":"extension-lifecycle","title":"Extension lifecycle"},{"level":"2","id":"managing-extensions-in-game","title":"Managing extensions in-game"},{"level":"2","id":"current-extension-families-in-this-repository","title":"Current extension families in this repository"},{"level":"2","id":"current-source-level-extension-reference","title":"Current source-level extension reference"},{"level":"2","id":"extension-jar-requirements","title":"Extension jar requirements"},{"level":"2","id":"recommended-structure","title":"Recommended structure"}],"excerpt":"AmazingTitles can load external extension jars from its Extensions folder."},"functions/hex-and-gradient-colors.md":{"title":"HEX and Gradient Colors","path":"functions/hex-and-gradient-colors.md","html":"<h1 id=\"hex-and-gradient-colors\">HEX and Gradient Colors</h1>\n<p>AmazingTitles uses <code>ColorTranslator</code> to process legacy colors, HEX colors, and gradients.</p>\n<h2 id=\"legacy-colors\">Legacy colors</h2>\n<p>Standard legacy codes work as expected:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">&amp;aGreen text\n&amp;cRed text\n&amp;lBold text</code></pre>\n<h2 id=\"hex-colors\">HEX colors</h2>\n<p>The plugin also supports direct HEX insertion in this format:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">&amp;{#FFAA00}Golden text</code></pre>\n<h2 id=\"rgb-gradients\">RGB gradients</h2>\n<p>Use this format for a HEX gradient:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">&lt;#FF0000&gt;Gradient text&lt;/#00FF00&gt;</code></pre>\n<p>The same style also works with legacy endpoints:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">&lt;&amp;c&gt;Gradient text&lt;/&amp;e&gt;</code></pre>\n<h2 id=\"compatibility-behavior\">Compatibility behavior</h2>\n<ul><li>On RGB-capable servers, gradients are expanded into per-character colors</li><li>On older servers without RGB support, gradient wrappers are stripped and the raw text remains</li></ul>\n<h2 id=\"practical-examples\">Practical examples</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">&amp;{#00AAFF}Loading world data\n&lt;#00AAFF&gt;&amp;lAmazing&lt;/#FF55FF&gt;Titles\n&lt;&amp;b&gt;Cold&lt;/&amp;f&gt; and clean</code></pre>\n<h2 id=\"where-it-applies\">Where it applies</h2>\n<p>You can use these formats in:</p>\n<ul><li>animation text</li><li>subtitles</li><li>notification symbols</li><li>notification text</li><li>interactive messages</li><li>extension-generated frames</li></ul>\n<h2 id=\"recommendation\">Recommendation</h2>\n<p>If you want one configuration to look acceptable on both old and new versions:</p>\n<ul><li>keep important content readable without RGB</li><li>use gradients as visual enhancement, not as the only signal</li></ul>","headings":[{"level":"1","id":"hex-and-gradient-colors","title":"HEX and Gradient Colors"},{"level":"2","id":"legacy-colors","title":"Legacy colors"},{"level":"2","id":"hex-colors","title":"HEX colors"},{"level":"2","id":"rgb-gradients","title":"RGB gradients"},{"level":"2","id":"compatibility-behavior","title":"Compatibility behavior"},{"level":"2","id":"practical-examples","title":"Practical examples"},{"level":"2","id":"where-it-applies","title":"Where it applies"},{"level":"2","id":"recommendation","title":"Recommendation"}],"excerpt":"AmazingTitles uses ColorTranslator to process legacy colors, HEX colors, and gradients."},"functions/plugin-functions.md":{"title":"Plugin Functions","path":"functions/plugin-functions.md","html":"<h1 id=\"plugin-functions\">Plugin Functions</h1>\n<p>This page summarizes the plugin features that ship in the main jar.</p>\n<h2 id=\"core-display-modules\">Core display modules</h2>\n<ul><li>Title dispatcher</li><li>Subtitle dispatcher</li><li>Action bar dispatcher</li><li>Boss bar dispatcher</li><li>Interactive chat sender</li><li>Smart notification sender</li></ul>\n<h2 id=\"built-in-systems\">Built-in systems</h2>\n<ul><li>Animation registry</li><li>Extension loader</li><li>SmartBar manager</li><li>Interactive message parser</li><li>Update notifier</li><li>CMI integration bootstrap</li></ul>\n<h2 id=\"main-command-handlers\">Main command handlers</h2>\n<p>The plugin command internally registers these handlers:</p>\n<ul><li><code>/at sendAnimation</code></li><li><code>/at sendNotification</code></li><li><code>/at sendMessage</code></li><li><code>/at pluginActions</code></li></ul>\n<h2 id=\"at-sendanimation\"><code>/at sendAnimation</code></h2>\n<p>Used to dispatch a built-in or extension animation to players.</p>\n<p>Syntax:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation &lt;Players&gt; &lt;arguments/@&gt; &lt;Animation&gt; [AnimationArguments] &lt;Text%subtitle%SubText&gt;</code></pre>\n<p>Examples:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation all p:TITLE,d:3,fps:20 NONE &amp;aWelcome\n/at sendAnimation Steve p:ACTIONBAR,d:4,fps:10 WAVES #00AAFF #FFFFFF &amp;bLoading...\n/at sendAnimation all p:TITLE,d:4,fps:12 FADE_IN_WRITER | &amp;dSeason Reset%subtitle%&amp;7Please wait</code></pre>\n<p>Detailed page: <a href=\"#/functions/sending-animations.md\">Sending Animations</a></p>\n<h2 id=\"at-sendnotification\"><code>/at sendNotification</code></h2>\n<p>Used to send SmartBar notifications.</p>\n<p>Syntax:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendNotification &lt;Players&gt; &lt;Duration&gt; &lt;Symbol&gt; &lt;Message&gt;</code></pre>\n<p>Example:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendNotification all 4 &amp;a+ &amp;fReward claimed</code></pre>\n<p>Detailed page: <a href=\"#/functions/sending-notifications.md\">Sending Notifications</a></p>\n<h2 id=\"at-sendmessage\"><code>/at sendMessage</code></h2>\n<p>Used to send interactive chat messages built from a raw mini-format.</p>\n<p>Syntax:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendMessage &lt;Players&gt; &lt;Message&gt;</code></pre>\n<p>Example:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendMessage all &lt;HOVER=&amp;eOpen releases,OPEN_URL=https://github.com/Kora-Studios-LLC/AmazingTitles/releases&gt;&amp;aClick here&lt;/&gt;</code></pre>\n<p>Detailed page: <a href=\"#/functions/sending-interactive-messages.md\">Sending Interactive Messages</a></p>\n<h2 id=\"at-pluginactions\"><code>/at pluginActions</code></h2>\n<p>Used to manage reloads and external extension jars.</p>\n<p>Supported actions seen in code:</p>\n<ul><li><code>extensionList</code></li><li><code>loadExtension</code></li><li><code>reloadExtension</code></li><li><code>unloadExtension</code></li><li><code>reloadExtensions</code></li><li><code>unloadExtensions</code></li><li><code>loadExtensions</code></li><li><code>reload</code></li></ul>\n<p>Examples:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at pluginActions extensionList\n/at pluginActions loadExtensions\n/at pluginActions reload</code></pre>\n<h2 id=\"built-in-animation-catalog\">Built-in animation catalog</h2>\n<p>The main plugin currently registers these default animations:</p>\n<ul><li><code>NONE</code></li><li><code>FLASHING_SYMBOL_WRAP</code></li><li><code>RAINBOW</code></li><li><code>WAVES</code></li><li><code>BOUNCE</code></li><li><code>FLASHING</code></li><li><code>SPLIT</code></li><li><code>WORDS_SPLIT</code></li><li><code>FROM_LEFT</code></li><li><code>FROM_RIGHT</code></li><li><code>FADE_IN</code></li><li><code>FADE_IN_WRITER</code></li><li><code>FROM_BOTH_SIDES</code></li><li><code>PULSING</code></li></ul>","headings":[{"level":"1","id":"plugin-functions","title":"Plugin Functions"},{"level":"2","id":"core-display-modules","title":"Core display modules"},{"level":"2","id":"built-in-systems","title":"Built-in systems"},{"level":"2","id":"main-command-handlers","title":"Main command handlers"},{"level":"2","id":"at-sendanimation","title":"/at sendAnimation"},{"level":"2","id":"at-sendnotification","title":"/at sendNotification"},{"level":"2","id":"at-sendmessage","title":"/at sendMessage"},{"level":"2","id":"at-pluginactions","title":"/at pluginActions"},{"level":"2","id":"built-in-animation-catalog","title":"Built-in animation catalog"}],"excerpt":"This page summarizes the plugin features that ship in the main jar."},"functions/sending-animations.md":{"title":"Sending Animations","path":"functions/sending-animations.md","html":"<h1 id=\"sending-animations\">Sending Animations</h1>\n<p>This page explains the built-in animation command and its argument parser.</p>\n<h2 id=\"command-syntax\">Command syntax</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation &lt;Players&gt; &lt;arguments/@&gt; &lt;Animation&gt; [AnimationArguments] &lt;Text%subtitle%SubText&gt;</code></pre>\n<h2 id=\"part-1-player-selector\">Part 1: Player selector</h2>\n<p>The first argument selects receivers.</p>\n<p>Supported forms:</p>\n<ul><li><code>all</code></li><li><code>Steve</code></li><li><code>Steve,Alex</code></li><li><code>-p:permission.node</code></li><li><code>-w:world_name</code></li></ul>\n<p>Examples:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">all\nSteve,Alex\n-p:vip.rank\n-w:world_nether</code></pre>\n<h2 id=\"part-2-display-argument-bundle\">Part 2: Display argument bundle</h2>\n<p>The second argument is a comma-separated bundle parsed by <code>ArgsHelper</code>.</p>\n<p>Supported tokens:</p>\n<ul><li><code>cc:PINK</code></li><li><code>cc:BLUE</code></li><li><code>cc:RED</code></li><li><code>cc:GREEN</code></li><li><code>cc:YELLOW</code></li><li><code>cc:PURPLE</code></li><li><code>cc:WHITE</code></li><li><code>p:TITLE</code></li><li><code>p:SUBTITLE</code></li><li><code>p:BOSSBAR</code></li><li><code>p:ACTIONBAR</code></li><li><code>d:&lt;seconds&gt;</code></li><li><code>fps:&lt;1-20&gt;</code></li></ul>\n<p>Example:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">p:TITLE,d:4,fps:20,cc:WHITE</code></pre>\n<p>Notes:</p>\n<ul><li><code>cc:</code> mainly matters for boss bar output</li><li><code>d:</code> is in seconds</li><li><code>fps:</code> is animation speed</li><li><code>p:BOSSBAR</code> falls back internally on old servers without boss bar support</li></ul>\n<h2 id=\"part-3-animation-name\">Part 3: Animation name</h2>\n<p>The third argument is the animation key, for example:</p>\n<ul><li><code>NONE</code></li><li><code>FADE_IN</code></li><li><code>WAVES</code></li><li><code>PULSING</code></li><li><code>EXTENSION_BOUNCE_CENTER_REVEAL</code></li></ul>\n<h2 id=\"part-4-animation-arguments\">Part 4: Animation arguments</h2>\n<p>Some animations require extra arguments before the text body.</p>\n<p>Examples:</p>\n<ul><li><code>WAVES</code> -&gt; <code>Color1 Color2</code></li><li><code>PULSING</code> -&gt; <code>Color1 Color2</code></li><li><code>FADE_IN_WRITER</code> -&gt; <code>WriterSymbol</code></li><li><code>FLASHING_SYMBOL_WRAP</code> -&gt; <code>Symbol</code></li></ul>\n<h2 id=\"part-5-main-text-and-subtitle\">Part 5: Main text and subtitle</h2>\n<p>The final text block may optionally include <code>%subtitle%</code>.</p>\n<p>Example:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">&amp;aMain title%subtitle%&amp;7Subtitle text</code></pre>\n<p>If <code>%subtitle%</code> is not present, only the main text is used.</p>\n<h2 id=\"example-commands\">Example commands</h2>\n<h3 id=\"static-title\">Static title</h3>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation all p:TITLE,d:3,fps:20 NONE &amp;aWelcome</code></pre>\n<h3 id=\"rgb-wave\">RGB wave</h3>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation all p:ACTIONBAR,d:5,fps:12 WAVES #00AAFF #FFFFFF &amp;bSynchronizing data</code></pre>\n<h3 id=\"writer-reveal-with-subtitle\">Writer reveal with subtitle</h3>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendAnimation Steve p:TITLE,d:4,fps:15 FADE_IN_WRITER | &amp;dAmazingTitles%subtitle%&amp;7Loading modules</code></pre>\n<h2 id=\"where-animations-come-from\">Where animations come from</h2>\n<p>Animations can come from two places:</p>\n<ul><li>built-in registrations in <code>PluginLoader.loadDefaultAnimations()</code></li><li>extension jars loaded into <code>plugins/AmazingTitles/Extensions</code></li></ul>\n<h2 id=\"troubleshooting\">Troubleshooting</h2>\n<p>If the command returns the help message, check:</p>\n<ul><li>the player selector</li><li>the display argument bundle</li><li>the animation name</li><li>the required animation arguments</li><li>whether your extension is loaded</li></ul>","headings":[{"level":"1","id":"sending-animations","title":"Sending Animations"},{"level":"2","id":"command-syntax","title":"Command syntax"},{"level":"2","id":"part-1-player-selector","title":"Part 1: Player selector"},{"level":"2","id":"part-2-display-argument-bundle","title":"Part 2: Display argument bundle"},{"level":"2","id":"part-3-animation-name","title":"Part 3: Animation name"},{"level":"2","id":"part-4-animation-arguments","title":"Part 4: Animation arguments"},{"level":"2","id":"part-5-main-text-and-subtitle","title":"Part 5: Main text and subtitle"},{"level":"2","id":"example-commands","title":"Example commands"},{"level":"3","id":"static-title","title":"Static title"},{"level":"3","id":"rgb-wave","title":"RGB wave"},{"level":"3","id":"writer-reveal-with-subtitle","title":"Writer reveal with subtitle"},{"level":"2","id":"where-animations-come-from","title":"Where animations come from"},{"level":"2","id":"troubleshooting","title":"Troubleshooting"}],"excerpt":"This page explains the built-in animation command and its argument parser."},"functions/sending-interactive-messages.md":{"title":"Sending Interactive Messages","path":"functions/sending-interactive-messages.md","html":"<h1 id=\"sending-interactive-messages\">Sending Interactive Messages</h1>\n<p>Interactive chat messages are built from a raw string mini-format and then converted into Bungee chat components.</p>\n<h2 id=\"command-syntax\">Command syntax</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendMessage &lt;Players&gt; &lt;Message&gt;</code></pre>\n<h2 id=\"raw-format\">Raw format</h2>\n<p>Interactive segments use this structure:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">&lt;ARGUMENTS&gt;Visible text&lt;/&gt;</code></pre>\n<p>Supported arguments:</p>\n<ul><li><code>HOVER=&lt;text&gt;</code></li><li><code>OPEN_URL=&lt;url&gt;</code></li><li><code>SUGGEST_COMMAND=&lt;command&gt;</code></li><li><code>RUN_COMMAND=&lt;command&gt;</code></li></ul>\n<p>You can combine multiple arguments with commas:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">&lt;HOVER=&amp;eOpen releases,OPEN_URL=https://github.com/Kora-Studios-LLC/AmazingTitles/releases&gt;&amp;aGitHub Releases&lt;/&gt;</code></pre>\n<h2 id=\"example-commands\">Example commands</h2>\n<h3 id=\"open-a-url\">Open a URL</h3>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendMessage all &lt;HOVER=&amp;eOpen releases,OPEN_URL=https://github.com/Kora-Studios-LLC/AmazingTitles/releases&gt;&amp;aClick here to update&lt;/&gt;</code></pre>\n<h3 id=\"suggest-a-command\">Suggest a command</h3>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendMessage Steve &lt;HOVER=&amp;7Suggest command,SUGGEST_COMMAND=/at pluginActions reload&gt;&amp;dReload AmazingTitles&lt;/&gt;</code></pre>\n<h3 id=\"run-a-command\">Run a command</h3>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendMessage Steve &lt;HOVER=&amp;7Run now,RUN_COMMAND=/at pluginActions extensionList&gt;&amp;aShow loaded extensions&lt;/&gt;</code></pre>\n<h2 id=\"plain-text-and-interactive-text-together\">Plain text and interactive text together</h2>\n<p>You can mix normal colored text and interactive sections:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">&amp;7Need help? &lt;HOVER=&amp;bOpen support,OPEN_URL=https://discord.com/invite/Ms7uAAAtcT&gt;&amp;bJoin Discord&lt;/&gt; &amp;7or &lt;HOVER=&amp;eOpen releases,OPEN_URL=https://github.com/Kora-Studios-LLC/AmazingTitles/releases&gt;&amp;eopen releases&lt;/&gt;</code></pre>\n<h2 id=\"important-parser-limitations\">Important parser limitations</h2>\n<p>The current parser is intentionally lightweight. Keep these rules in mind:</p>\n<ul><li>Argument values are split by commas</li><li>Values are not quoted</li><li>Avoid commas inside hover text or command values</li><li>Keep raw tags balanced with <code>&lt;/&gt;</code></li></ul>\n<h2 id=\"api-equivalent\">API equivalent</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-java\">AmazingTitles.sendInteractiveMessage(\n    &quot;&lt;HOVER=&amp;eOpen releases,OPEN_URL=https://github.com/Kora-Studios-LLC/AmazingTitles/releases&gt;&amp;aClick here&lt;/&gt;&quot;,\n    player\n);</code></pre>","headings":[{"level":"1","id":"sending-interactive-messages","title":"Sending Interactive Messages"},{"level":"2","id":"command-syntax","title":"Command syntax"},{"level":"2","id":"raw-format","title":"Raw format"},{"level":"2","id":"example-commands","title":"Example commands"},{"level":"3","id":"open-a-url","title":"Open a URL"},{"level":"3","id":"suggest-a-command","title":"Suggest a command"},{"level":"3","id":"run-a-command","title":"Run a command"},{"level":"2","id":"plain-text-and-interactive-text-together","title":"Plain text and interactive text together"},{"level":"2","id":"important-parser-limitations","title":"Important parser limitations"},{"level":"2","id":"api-equivalent","title":"API equivalent"}],"excerpt":"Interactive chat messages are built from a raw string mini-format and then converted into Bungee chat components."},"functions/sending-notifications.md":{"title":"Sending Notifications","path":"functions/sending-notifications.md","html":"<h1 id=\"sending-notifications\">Sending Notifications</h1>\n<p>AmazingTitles includes a SmartBar notification system designed for short animated action bar notices.</p>\n<h2 id=\"command-syntax\">Command syntax</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendNotification &lt;Players&gt; &lt;Duration&gt; &lt;Symbol&gt; &lt;Message&gt;</code></pre>\n<h2 id=\"arguments\">Arguments</h2>\n<ul><li><code>Players</code>: same selector rules as animation dispatch</li><li><code>Duration</code>: seconds as an integer</li><li><code>Symbol</code>: leading icon or prefix</li><li><code>Message</code>: notification body</li></ul>\n<h2 id=\"example-commands\">Example commands</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at sendNotification all 4 &amp;a+ &amp;fReward claimed\n/at sendNotification Steve,Alex 6 &amp;e! &amp;6Server restart in 60 seconds\n/at sendNotification -p:staff.notify 3 &amp;cX &amp;fA moderation action was completed</code></pre>\n<h2 id=\"behavior-notes\">Behavior notes</h2>\n<ul><li>The symbol and message are colorized before display</li><li>Notifications animate in and animate out automatically</li><li>Notifications are routed through each player&#x27;s SmartBar instance</li></ul>\n<h2 id=\"api-equivalent\">API equivalent</h2>\n<p>The public API exposes the same feature through <code>SmartNotification</code>:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-java\">AmazingTitles.sendNotification(new SmartNotification(4, &quot;&amp;a+&quot;, &quot;&amp;fReward claimed&quot;), player);</code></pre>\n<h2 id=\"best-practices\">Best practices</h2>\n<ul><li>Keep the symbol short</li><li>Keep the text compact so it fits action bar space</li><li>Avoid very long durations unless the notification is critical</li></ul>","headings":[{"level":"1","id":"sending-notifications","title":"Sending Notifications"},{"level":"2","id":"command-syntax","title":"Command syntax"},{"level":"2","id":"arguments","title":"Arguments"},{"level":"2","id":"example-commands","title":"Example commands"},{"level":"2","id":"behavior-notes","title":"Behavior notes"},{"level":"2","id":"api-equivalent","title":"API equivalent"},{"level":"2","id":"best-practices","title":"Best practices"}],"excerpt":"AmazingTitles includes a SmartBar notification system designed for short animated action bar notices."},"help-center.md":{"title":"Help Center","path":"help-center.md","html":"<h1 id=\"help-center\">Help Center</h1>\n<p>This page is designed for support, FAQs, and common troubleshooting topics once the content is imported into GitBook.</p>\n<h2 id=\"common-questions\">Common questions</h2>\n<h3 id=\"why-does-boss-bar-output-not-appear-on-188\">Why does boss bar output not appear on 1.8.8?</h3>\n<p>Minecraft <code>1.8.8</code> does not provide Bukkit boss bars in the way modern versions do. AmazingTitles falls back internally instead of exposing a native boss bar there.</p>\n<h3 id=\"why-are-hex-colors-not-showing-correctly\">Why are HEX colors not showing correctly?</h3>\n<p>HEX and gradients depend on RGB-capable server support. On older versions, formatting may degrade to simpler color output.</p>\n<h3 id=\"where-do-i-place-extension-jars\">Where do I place extension jars?</h3>\n<p>Use:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">plugins/AmazingTitles/Extensions</code></pre>\n<h3 id=\"how-do-i-reload-the-plugin-or-extensions\">How do I reload the plugin or extensions?</h3>\n<p>Use the <code>pluginActions</code> command family:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">/at pluginActions reload\n/at pluginActions loadExtensions\n/at pluginActions reloadExtensions</code></pre>\n<h3 id=\"where-does-amazingtitles-check-for-updates\">Where does AmazingTitles check for updates?</h3>\n<p>The current build checks GitHub Releases:</p>\n<p><a href=\"https://github.com/Kora-Studios-LLC/AmazingTitles/releases\" target=\"_blank\" rel=\"noreferrer\">https://github.com/Kora-Studios-LLC/AmazingTitles/releases</a></p>\n<h2 id=\"support-links\">Support links</h2>\n<ul><li>Releases: <a href=\"https://github.com/Kora-Studios-LLC/AmazingTitles/releases\" target=\"_blank\" rel=\"noreferrer\">https://github.com/Kora-Studios-LLC/AmazingTitles/releases</a></li><li>Discord: <a href=\"https://discord.com/invite/Ms7uAAAtcT\" target=\"_blank\" rel=\"noreferrer\">https://discord.com/invite/Ms7uAAAtcT</a></li></ul>\n<h2 id=\"suggested-gitbook-use\">Suggested GitBook use</h2>\n<p>After importing these pages into GitBook, this page is a good place to add:</p>\n<ul><li>contact blocks</li><li>issue reporting instructions</li><li>server owner troubleshooting checklists</li><li>screenshots or embedded videos</li></ul>","headings":[{"level":"1","id":"help-center","title":"Help Center"},{"level":"2","id":"common-questions","title":"Common questions"},{"level":"3","id":"why-does-boss-bar-output-not-appear-on-188","title":"Why does boss bar output not appear on 1.8.8?"},{"level":"3","id":"why-are-hex-colors-not-showing-correctly","title":"Why are HEX colors not showing correctly?"},{"level":"3","id":"where-do-i-place-extension-jars","title":"Where do I place extension jars?"},{"level":"3","id":"how-do-i-reload-the-plugin-or-extensions","title":"How do I reload the plugin or extensions?"},{"level":"3","id":"where-does-amazingtitles-check-for-updates","title":"Where does AmazingTitles check for updates?"},{"level":"2","id":"support-links","title":"Support links"},{"level":"2","id":"suggested-gitbook-use","title":"Suggested GitBook use"}],"excerpt":"This page is designed for support, FAQs, and common troubleshooting topics once the content is imported into GitBook."},"Home.md":{"title":"AmazingTitles Home","path":"Home.md","html":"<h1 id=\"amazingtitles-home\">AmazingTitles Home</h1>\n<p>Welcome to the official documentation home for AmazingTitles.</p>\n<p>AmazingTitles is a Spigot and Paper plugin focused on animated text delivery across titles, subtitles, action bars, boss bars, smart notifications, interactive chat messages, extensions, and developer-facing API features.</p>\n<h2 id=\"why-amazingtitles\">Why AmazingTitles</h2>\n<ul><li>built-in animation system for common title effects</li><li>extension support for custom animation packs</li><li>interactive message utilities for chat-based UX</li><li>SmartBar notification support</li><li>compatibility range from <code>1.8.8</code> to <code>1.21.11</code></li><li>public API for custom integrations and developer tools</li></ul>\n<h2 id=\"start-here\">Start here</h2>\n<ul><li><a href=\"#/documentation/getting-started.md\">Quickstart</a></li><li><a href=\"#/documentation/installation-and-setup.md\">Installation and Setup</a></li><li><a href=\"#/plugin-details.md\">Plugin Details</a></li><li><a href=\"#/functions/plugin-functions.md\">Plugin Functions</a></li></ul>\n<h2 id=\"documentation-areas\">Documentation areas</h2>\n<h3 id=\"documentation\">Documentation</h3>\n<p>Administrator and usage guides:</p>\n<ul><li><a href=\"#/documentation/README.md\">Documentation Overview</a></li><li><a href=\"#/functions/sending-animations.md\">Sending Animations</a></li><li><a href=\"#/functions/sending-notifications.md\">Sending Notifications</a></li><li><a href=\"#/functions/sending-interactive-messages.md\">Sending Interactive Messages</a></li><li><a href=\"#/functions/hex-and-gradient-colors.md\">HEX and Gradient Colors</a></li></ul>\n<h3 id=\"api-reference\">API Reference</h3>\n<p>Developer-facing integration pages:</p>\n<ul><li><a href=\"#/api-reference/README.md\">API Reference Overview</a></li><li><a href=\"#/api/creating-amazingextension.md\">Creating AmazingExtension</a></li><li><a href=\"#/api/creating-custom-animations.md\">Creating Custom Animations</a></li><li><a href=\"#/api/creating-custom-subcommand.md\">Creating Custom SubCommand</a></li><li><a href=\"#/api/other-api-stuff.md\">Other API Stuff</a></li></ul>\n<h3 id=\"ecosystem\">Ecosystem</h3>\n<ul><li><a href=\"#/extensions/overview.md\">Extensions Overview</a></li><li><a href=\"#/integrations/cmi-integration.md\">CMI Integration</a></li><li><a href=\"#/animations/none.md\">Built-in Animations</a></li></ul>\n<h2 id=\"releases-and-support\">Releases and support</h2>\n<ul><li><a href=\"#/changelog.md\">Changelog</a></li><li><a href=\"#/help-center.md\">Help Center</a></li><li>GitHub Releases: <a href=\"https://github.com/Kora-Studios-LLC/AmazingTitles/releases\" target=\"_blank\" rel=\"noreferrer\">https://github.com/Kora-Studios-LLC/AmazingTitles/releases</a></li><li>Support Discord: <a href=\"https://discord.com/invite/Ms7uAAAtcT\" target=\"_blank\" rel=\"noreferrer\">https://discord.com/invite/Ms7uAAAtcT</a></li></ul>\n<h2 id=\"import-note-for-gitbook\">Import note for GitBook</h2>\n<p>If you want a dedicated landing page in GitBook instead of using <code>README.md</code> as the default page, this file can be used as the site home page after import.</p>","headings":[{"level":"1","id":"amazingtitles-home","title":"AmazingTitles Home"},{"level":"2","id":"why-amazingtitles","title":"Why AmazingTitles"},{"level":"2","id":"start-here","title":"Start here"},{"level":"2","id":"documentation-areas","title":"Documentation areas"},{"level":"3","id":"documentation","title":"Documentation"},{"level":"3","id":"api-reference","title":"API Reference"},{"level":"3","id":"ecosystem","title":"Ecosystem"},{"level":"2","id":"releases-and-support","title":"Releases and support"},{"level":"2","id":"import-note-for-gitbook","title":"Import note for GitBook"}],"excerpt":"Welcome to the official documentation home for AmazingTitles."},"integrations/cmi-integration.md":{"title":"CMI Integration","path":"integrations/cmi-integration.md","html":"<h1 id=\"cmi-integration\">CMI Integration</h1>\n<p>AmazingTitles contains a built-in integration bootstrap for <code>CMI</code>.</p>\n<h2 id=\"how-it-loads\">How it loads</h2>\n<p>On plugin enable, AmazingTitles checks whether the <code>CMI</code> plugin is present. If it is, the CMI integration is instantiated and registers its listeners automatically.</p>\n<h2 id=\"integration-file\">Integration file</h2>\n<p>The integration stores its config here:</p>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-text\">plugins/AmazingTitles/Integrations/CMI-Integration.yml</code></pre>\n<h2 id=\"supported-cmi-events-in-code\">Supported CMI events in code</h2>\n<ul><li>portal use</li><li>teleport request</li><li>teleport</li><li>AFK enter</li><li>AFK leave</li><li>balance change</li></ul>\n<h2 id=\"conditions\">Conditions</h2>\n<p>Current condition keys supported by the helper:</p>\n<ul><li><code>permission::&lt;node&gt;</code></li><li><code>world::&lt;world_name&gt;</code></li></ul>\n<h2 id=\"executions\">Executions</h2>\n<p>Executions are plain console commands. Placeholders are replaced before dispatch.</p>\n<h2 id=\"example-config\">Example config</h2>\n<pre class=\"code-block\"><button class=\"copy-code\" type=\"button\">Copy</button><code class=\"language-yaml\">Teleport:\n  Conditions:\n    - &quot;world::world&quot;\n  Executions:\n    - &quot;at sendAnimation {Player} p:TITLE,d:3,fps:20 NONE &amp;aTeleported%subtitle%&amp;7{World} {X} {Y} {Z}&quot;\n\nAfkEnter:\n  Conditions: []\n  Executions:\n    - &quot;at sendNotification {Player} 4 &amp;e! &amp;6You are now AFK&quot;</code></pre>\n<h2 id=\"common-placeholders\">Common placeholders</h2>\n<p>Depending on the event, the integration exposes values such as:</p>\n<ul><li><code>{Player}</code></li><li><code>{PortalName}</code></li><li><code>{OfferingPlayer}</code></li><li><code>{AcceptingPlayer}</code></li><li><code>{World}</code></li><li><code>{X}</code></li><li><code>{Y}</code></li><li><code>{Z}</code></li><li><code>{TeleportType}</code></li><li><code>{From}</code></li><li><code>{To}</code></li></ul>\n<h2 id=\"practical-note\">Practical note</h2>\n<p>Because executions are dispatched as console commands, this integration works best when you reuse AmazingTitles commands directly.</p>","headings":[{"level":"1","id":"cmi-integration","title":"CMI Integration"},{"level":"2","id":"how-it-loads","title":"How it loads"},{"level":"2","id":"integration-file","title":"Integration file"},{"level":"2","id":"supported-cmi-events-in-code","title":"Supported CMI events in code"},{"level":"2","id":"conditions","title":"Conditions"},{"level":"2","id":"executions","title":"Executions"},{"level":"2","id":"example-config","title":"Example config"},{"level":"2","id":"common-placeholders","title":"Common placeholders"},{"level":"2","id":"practical-note","title":"Practical note"}],"excerpt":"AmazingTitles contains a built-in integration bootstrap for CMI."},"plugin-details.md":{"title":"Plugin Details","path":"plugin-details.md","html":"<h1 id=\"plugin-details\">Plugin Details</h1>\n<p>This page covers the current build, runtime behavior, folder layout, permissions, and high-level capabilities.</p>\n<h2 id=\"identity\">Identity</h2>\n<ul><li>Name: <code>AmazingTitles</code></li><li>Namespace: <code>org.korastudios.amazingtitles</code></li><li>Plugin main class: <code>org.korastudios.amazingtitles.code.internal.Booter</code></li><li>Command aliases: <code>/amazingtitles</code>, <code>/at</code></li><li>Soft dependency: <code>CMI</code></li></ul>\n<h2 id=\"what-the-plugin-does\">What the plugin does</h2>\n<p>AmazingTitles is designed to dispatch formatted text to players in several display channels:</p>\n<ul><li>Title</li><li>Subtitle</li><li>Action Bar</li><li>Boss Bar</li><li>Interactive chat</li><li>Smart notifications through the action bar layer</li></ul>\n<p>It also includes:</p>\n<ul><li>Built-in animation presets</li><li>Extension loading through jar files</li><li>CMI integration hooks</li><li>A public API for custom animations, extensions, notifications, and subcommands</li></ul>\n<h2 id=\"runtime-compatibility\">Runtime compatibility</h2>\n<ul><li>Java target in modules: Java 8 bytecode</li><li>Project build currently compiles with JDK 21</li><li>Supported Minecraft range in this repository: <code>1.8.8</code> to <code>1.21.11</code></li></ul>\n<h3 id=\"rgb-and-hex-support\">RGB and HEX support</h3>\n<p>RGB formatting depends on runtime support exposed by the server chat color API.</p>\n<ul><li>Modern versions: HEX and gradients are available</li><li>Older versions: HEX and gradients gracefully degrade to plain text or legacy color behavior</li></ul>\n<h2 id=\"data-folders\">Data folders</h2>\n<p>When the plugin runs, it uses these directories inside the plugin data folder:</p>\n<ul><li><code>plugins/AmazingTitles/Extensions</code></li><li><code>plugins/AmazingTitles/Integrations</code></li></ul>\n<h2 id=\"built-in-command-handlers\">Built-in command handlers</h2>\n<p>The main command is routed into four built-in handler families:</p>\n<ul><li><code>sendAnimation</code></li><li><code>sendNotification</code></li><li><code>sendMessage</code></li><li><code>pluginActions</code></li></ul>\n<p>See <a href=\"#/functions/plugin-functions.md\">Plugin Functions</a> for syntax details.</p>\n<h2 id=\"permissions-seen-in-code\">Permissions seen in code</h2>\n<p>These permission nodes are currently used by command and update logic:</p>\n<ul><li><code>amazingtitles.command</code></li><li><code>amazingtitles.admin</code></li><li><code>at.animations</code></li><li><code>at.notifications</code></li><li><code>at.messages</code></li><li><code>at.plugin</code></li></ul>\n<h2 id=\"update-notifications\">Update notifications</h2>\n<p>The update notifier reads the latest release tag from GitHub instead of Spigot.</p>\n<ul><li>Releases page: <a href=\"https://github.com/Kora-Studios-LLC/AmazingTitles/releases\" target=\"_blank\" rel=\"noreferrer\">https://github.com/Kora-Studios-LLC/AmazingTitles/releases</a></li><li>API endpoint used by the checker: <code>https://api.github.com/repos/Kora-Studios-LLC/AmazingTitles/releases/latest</code></li></ul>\n<p>You can toggle update notifications in <code>options.yml</code> with <code>UpdateNotifier</code>.</p>\n<h2 id=\"smartbar-notes\">SmartBar notes</h2>\n<p><code>options.yml</code> exposes a built-in static smart bar configuration with:</p>\n<ul><li>enabled toggle</li><li>animation name</li><li>fps</li><li>animation arguments</li><li>display text</li><li>notification interruption toggle</li></ul>\n<p>That makes it possible to run an always-on animated action bar without writing code.</p>","headings":[{"level":"1","id":"plugin-details","title":"Plugin Details"},{"level":"2","id":"identity","title":"Identity"},{"level":"2","id":"what-the-plugin-does","title":"What the plugin does"},{"level":"2","id":"runtime-compatibility","title":"Runtime compatibility"},{"level":"3","id":"rgb-and-hex-support","title":"RGB and HEX support"},{"level":"2","id":"data-folders","title":"Data folders"},{"level":"2","id":"built-in-command-handlers","title":"Built-in command handlers"},{"level":"2","id":"permissions-seen-in-code","title":"Permissions seen in code"},{"level":"2","id":"update-notifications","title":"Update notifications"},{"level":"2","id":"smartbar-notes","title":"SmartBar notes"}],"excerpt":"This page covers the current build, runtime behavior, folder layout, permissions, and high-level capabilities."},"README.md":{"title":"AmazingTitles","path":"README.md","html":"<h1 id=\"amazingtitles\">AmazingTitles</h1>\n<p>Animated titles, subtitles, action bars, boss bars, notifications, interactive messages, extensions, and API tooling for Spigot and Paper servers.</p>\n<blockquote><p>This wiki is organized to import cleanly into GitBook and follows a structure closer to a product documentation site: documentation, API reference, changelog, and help pages.</p></blockquote>\n<h2 id=\"at-a-glance\">At a glance</h2>\n<ul><li>Plugin version: <code>6.0-SNAPSHOT</code></li><li>Namespace: <code>org.korastudios.amazingtitles</code></li><li>Main command: <code>/amazingtitles</code> and <code>/at</code></li><li>Version range in this build: <code>1.8.8</code> to <code>1.21.11</code></li><li>Update source: GitHub Releases</li></ul>\n<h2 id=\"jump-right-in\">Jump right in</h2>\n<ul><li><a href=\"#/documentation/getting-started.md\">Quickstart</a></li><li><a href=\"#/plugin-details.md\">Plugin Details</a></li><li><a href=\"#/documentation/README.md\">Documentation Overview</a></li><li><a href=\"#/api-reference/README.md\">API Reference Overview</a></li></ul>\n<h2 id=\"explore-the-docs\">Explore the docs</h2>\n<ul><li><a href=\"#/functions/plugin-functions.md\">Plugin Functions</a></li><li><a href=\"#/functions/sending-animations.md\">Sending Animations</a></li><li><a href=\"#/functions/sending-notifications.md\">Sending Notifications</a></li><li><a href=\"#/functions/sending-interactive-messages.md\">Sending Interactive Messages</a></li><li><a href=\"#/functions/hex-and-gradient-colors.md\">HEX and Gradient Colors</a></li><li><a href=\"#/animations/none.md\">Built-in Animations</a></li><li><a href=\"#/extensions/overview.md\">Extensions</a></li><li><a href=\"#/integrations/cmi-integration.md\">CMI Integration</a></li></ul>\n<h2 id=\"release-and-support\">Release and support</h2>\n<ul><li><a href=\"#/changelog.md\">Changelog</a></li><li><a href=\"#/help-center.md\">Help Center</a></li><li>GitHub Releases: <a href=\"https://github.com/Kora-Studios-LLC/AmazingTitles/releases\" target=\"_blank\" rel=\"noreferrer\">https://github.com/Kora-Studios-LLC/AmazingTitles/releases</a></li><li>Support Discord: <a href=\"https://discord.com/invite/Ms7uAAAtcT\" target=\"_blank\" rel=\"noreferrer\">https://discord.com/invite/Ms7uAAAtcT</a></li></ul>\n<h2 id=\"compatibility-notes\">Compatibility notes</h2>\n<ul><li>Modern RGB-capable servers support HEX and gradients.</li><li>Older versions such as <code>1.8.8</code> do not provide native boss bars, so that display mode falls back internally.</li><li>External extension jars are loaded from <code>plugins/AmazingTitles/Extensions</code>.</li></ul>","headings":[{"level":"1","id":"amazingtitles","title":"AmazingTitles"},{"level":"2","id":"at-a-glance","title":"At a glance"},{"level":"2","id":"jump-right-in","title":"Jump right in"},{"level":"2","id":"explore-the-docs","title":"Explore the docs"},{"level":"2","id":"release-and-support","title":"Release and support"},{"level":"2","id":"compatibility-notes","title":"Compatibility notes"}],"excerpt":"Animated titles, subtitles, action bars, boss bars, notifications, interactive messages, extensions, and API tooling for Spigot and Paper servers."}}};